// Helper: Get webhook data from either Webhook or Webhook1
const getWebhookData = () => {
  try { const w = $('Webhook'); if (w && w.first()) return w.first().json; } catch (e) {}
  try { const w1 = $('Webhook1'); if (w1 && w1.first()) return w1.first().json; } catch (e) {}
  return {};
};
const webhookData = getWebhookData();

// Get data from each branch
const illustrationGuide = $('Code in JavaScript').first().json.illustrationGuide;
const blogpost_draft = $('Code in JavaScript1').first().json.blogpost_draft;

// Get properties from webhook data (supports both Webhook and Webhook1)
const props = webhookData.body?.data?.properties || {};

// Extract relevant fields safely
const title = String(props.Name?.title?.[0]?.plain_text || '');
const description = String(props.Description?.rich_text?.[0]?.plain_text || '');
const imageGenDescription = String(props['Image Gen Description']?.rich_text?.[0]?.plain_text || '');
const pitch = String(props.Pitch?.rich_text?.[0]?.plain_text || '');

// Build context string with only non-empty fields
const contextParts = [];
if (title) contextParts.push('Title: ' + title);
if (description) contextParts.push('Description: ' + description);
if (pitch) contextParts.push('Pitch: ' + pitch);

const pageContext = contextParts.join('\n');

return [{
  json: {
    illustrationGuide: illustrationGuide,
    blogpost_draft: blogpost_draft,
    page_context: pageContext,
    image_gen_description: imageGenDescription
  }
}];

// Get the image description from LLM
const imageDescription = $('Basic LLM Chain').first().json.output?.imageDescription || '';

// Get parser output for aspect ratio and reference instructions
const parserOutput = $('Parameter Parser').first().json.output || {};
const aspectRatio = parserOutput.aspectRatio || '16:9';
const referenceUsageInstruction = parserOutput.referenceUsageInstruction || null;

// Get illustration guide for context (optional inclusion in prompt)
const illustrationGuide = $('Code in JavaScript').first().json.illustrationGuide || '';

// Get reference image from Google Drive Download node
let referenceImages = [];
try {
  const downloadNode = $('Download file');
  if (downloadNode && downloadNode.first().binary?.data) {
    const binaryMeta = downloadNode.first().binary.data;
    // In filesystem-v2 storage, .data is a reference ID, not base64.
    // Use helpers to read the actual binary buffer from storage.
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    const base64Data = buffer.toString('base64');
    referenceImages.push({
      base64: base64Data,
      mimeType: binaryMeta.mimeType || 'image/png'
    });
  }
} catch (e) {
  referenceImages = [];
}

// Build the parts array
const parts = [];

if (referenceImages.length > 0) {
  for (let i = 0; i < referenceImages.length; i++) {
    parts.push({
      inlineData: {
        mimeType: referenceImages[i].mimeType,
        data: referenceImages[i].base64
      }
    });
  }

  // Build reference instruction based on user preference
  let refInstruction = referenceUsageInstruction 
    ? `Using ${referenceUsageInstruction} from the reference image above`
    : 'Using the exact visual style of this reference image — including color palette, lighting, textures, polygon density, and artistic treatment';

  parts.push({
    text: `${refInstruction}, generate a completely new image based on the following description. The content should match the description precisely.

IMAGE DESCRIPTION:
${imageDescription}`
  });

} else {
  const styleReminder = `
