- Lowpoly 3D render with visible triangular facets
- Space/lunar environment theme
- Soft diffuse lighting with subtle shadows
- Brand colors: cyan (#1fb1ea) and orange (#d36600) as accents
- Clean minimal aesthetic, retro-futurism
- Medium-low polygon count (visible geometric mesh)
`;

  parts.push({
    text: `Generate an image following these specifications:
${styleReminder}
IMAGE DESCRIPTION:
${imageDescription}`
  });
}

// Build the complete request body with aspect ratio in generationConfig.imageConfig
const requestBody = {
  contents: [{
    parts: parts
  }],
  generationConfig: {
    responseModalities: ["IMAGE", "TEXT"],
    imageConfig: {
      aspectRatio: aspectRatio
    }
  }
};

return [{
  json: {
    requestBody,
    _meta: {
      hasReferenceImages: referenceImages.length > 0,
      referenceImageCount: referenceImages.length,
      descriptionLength: imageDescription.length,
      aspectRatio: aspectRatio,
      referenceUsageInstruction: referenceUsageInstruction
    }
  }
}];

// Helper: Get webhook data from either Webhook or Webhook1
const getWebhookData = () => {
  try { const w = $('Webhook'); if (w && w.first()) return w.first().json; } catch (e) {}
  try { const w1 = $('Webhook1'); if (w1 && w1.first()) return w1.first().json; } catch (e) {}
  return {};
};
const webhookData = getWebhookData();

const response = $input.first().json;

// Get imageTitle from LLM output
const imageTitle = $('Basic LLM Chain').first().json.output?.imageTitle || 'untitled';

// Get created_time from webhook (supports both Webhook and Webhook1)
const createdTime = webhookData.body?.data?.created_time;
const datePrefix = createdTime 
  ? new Date(createdTime).toISOString().slice(0, 10) // Gets YYYY-MM-DD
  : new Date().toISOString().slice(0, 10);

// Convert title to kebab-case slug
const titleSlug = imageTitle
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')  // Replace non-alphanumeric with hyphens
  .replace(/^-|-$/g, '');        // Remove leading/trailing hyphens

// Build filename
const fileName = `${datePrefix}_${titleSlug}.png`;

// Gemini returns image in candidates[0].content.parts[].inlineData
let imageBase64 = null;
let mimeType = 'image/png';

if (response.candidates && response.candidates[0]?.content?.parts) {
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      imageBase64 = part.inlineData.data;
      mimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
}

if (!imageBase64) {
  throw new Error('No image data found in Gemini response');
}

return [{
  json: {
    mimeType,
    fileName,
    imageTitle,
    datePrefix
  },
  binary: {
    image: {
      data: imageBase64,
      mimeType: mimeType,
      fileName: fileName
    }
  }
}];

